import{_ as e,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Ustawienia przesyłania","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/index.md","filePath":"pl-PL/upload/index.md","lastUpdated":1781962217000}'),n={name:"pl-PL/upload/index.md"};function l(t,a,d,s,z,c){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="ustawienia-przesyłania" tabindex="-1">Ustawienia przesyłania <a class="header-anchor" href="#ustawienia-przesyłania" aria-label="Permalink to &quot;Ustawienia przesyłania&quot;">​</a></h1><p>Ten rozdział ma tę samą kolejność kanałów co strona Ustawienia systemowe, więc możesz od razu przejść do dostawcy pamięci, którego konfigurujesz.</p><h2 id="jak-zorganizowano-ten-rozdział" tabindex="-1">Jak zorganizowano ten rozdział <a class="header-anchor" href="#jak-zorganizowano-ten-rozdział" aria-label="Permalink to &quot;Jak zorganizowano ten rozdział&quot;">​</a></h2><ul><li>Każdy dostawca ma osobną stronę. Oddzielenie 13 kanałów przesyłania ułatwia śledzenie kroków konfiguracji.</li><li>Zrzuty ekranu znajdują się w <code>../../image/upload/provider-name/</code> i są odwoływane lokalnie z poszczególnych stron.</li><li>Nazwy pól są możliwie bliskie interfejsowi produktu. Techniczne nazwy, takie jak <code>Endpoint</code>, <code>Client ID</code>, <code>Access Token</code> i <code>Refresh Token</code>, pozostają bez sztucznego tłumaczenia.</li></ul><h2 id="lista-kanałow" tabindex="-1">Lista kanałów <a class="header-anchor" href="#lista-kanałow" aria-label="Permalink to &quot;Lista kanałów&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="co-obejmuje-ten-rozdział" tabindex="-1">Co obejmuje ten rozdział <a class="header-anchor" href="#co-obejmuje-ten-rozdział" aria-label="Permalink to &quot;Co obejmuje ten rozdział&quot;">​</a></h2><ul><li>Jak dodać każdy kanał przesyłania.</li><li>Jakie dane dostępowe, identyfikatory lub uprawnienia trzeba przygotować wcześniej.</li><li>Jak sprawdzić, czy kanał jest gotowy do przesyłania plików.</li></ul><p>Szczegóły dotyczące rozwiązywania problemów, limitów i dobrych praktyk znajdują się przy konkretnych dostawcach.</p>',9)])])}const k=e(n,[["render",l]]);export{u as __pageData,k as default};
